O exemplo abaixo ilustra um serviço com:

• idempotência por hash de payload normalizado;
• fila para desacoplar request e render;
• worker isolado para renderização;
• timeouts e retry com limites.

A renderização é representada por uma função renderPdf(doc) (substitua pelo seu motor real). O foco é o pipeline.

content.content:
import crypto from "node:crypto";

function stableStringify(obj) {
  // Stringify determinístico (ordena chaves) para hashing confiável.
  const allKeys = [];
  JSON.stringify(obj, (k, v) => (allKeys.push(k), v));
  allKeys.sort();
  return JSON.stringify(obj, allKeys);
}

function sha256(input) {
  return crypto.createHash("sha256").update(input).digest("hex");
}

export async function createPdfJob(payload, templateVersion) {
  const normalized = {
    templateVersion,
    locale: "pt-BR",
    data: payload,
  };

  const payloadHash = sha256(stableStringify(normalized));
  const key = `pdf/${templateVersion}/${payloadHash}.pdf`;

  // 1) Deduplicação: se já existe, retorne referência
  const existing = await storage.exists(key);
  if (existing) {
    return { status: "ready", key, payloadHash };
  }

  // 2) Idempotência do job: enfileire apenas uma vez
  const jobId = await queue.enqueueOnce({ key, payloadHash, normalized }, payloadHash);
  return { status: "queued", jobId, key, payloadHash };
}

// Worker
export async function workerLoop() {
  for await (const job of queue.consume()) {
    const { key, payloadHash, normalized } = job.data;

    const timeoutMs = 30_000;
    const startedAt = Date.now();

    try {
      const doc = buildDocumentIR(normalized); // documento canônico

      const pdfBuffer = await withTimeout(renderPdf(doc), timeoutMs);

      await storage.put(key, pdfBuffer, {
        contentType: "application/pdf",
        metadata: { payloadHash, templateVersion: normalized.templateVersion },
      });

      metrics.timing("pdf.render.ms", Date.now() - startedAt);
      metrics.count("pdf.render.ok", 1);
      logs.info({ payloadHash, key }, "pdf_render_ok");

      await job.ack();
    } catch (err) {
      metrics.count("pdf.render.err", 1);
      logs.error({ err, payloadHash, key }, "pdf_render_failed");

      // Retry controlado
      if (job.attempts < 3) await job.retry({ backoffMs: 2_000 });
      else await job.deadLetter();
    }
  }
}

function withTimeout(promise, ms) {
  return new Promise((resolve, reject) => {
    const t = setTimeout(() => reject(new Error("render_timeout")), ms);
    promise.then(
      (v) => (clearTimeout(t), resolve(v)),
      (e) => (clearTimeout(t), reject(e))
    );
  });
}
